import asyncio, os, json
import anthropic
from mcp import ClientSession, StdioServerParameters
from mcp.client.stdio import stdio_client

GITHUB = StdioServerParameters(
    command="npx", args=["-y", "@modelcontextprotocol/server-github"],
    env={"GITHUB_PERSONAL_ACCESS_TOKEN": os.environ["GITHUB_TOKEN"]},
)
FILESYSTEM = StdioServerParameters(
    command="npx",
    args=["-y", "@modelcontextprotocol/server-filesystem", "/tmp/workspace"],
)
FETCH = StdioServerParameters(
    command="npx", args=["-y", "@modelcontextprotocol/server-fetch"],
)

client = anthropic.Anthropic()

async def build_tool_registry(sessions: dict[str, ClientSession]) -> dict:
    registry = {}
    for server_name, session in sessions.items():
        tools = await session.list_tools()
        for tool in tools.tools:
            registry[f"{server_name}__{tool.name}"] = {
                "session": session,
                "tool": tool,
                "anthropic_def": {
                    "name": f"{server_name}__{tool.name}",
                    "description": tool.description,
                    "input_schema": tool.inputSchema,
                },
            }
    return registry

async def run_review_agent(pr_url: str):
    async with (
        stdio_client(GITHUB) as (r1, w1),
        stdio_client(FILESYSTEM) as (r2, w2),
        stdio_client(FETCH) as (r3, w3),
    ):
        async with (
            ClientSession(r1, w1) as gh,
            ClientSession(r2, w2) as fs,
            ClientSession(r3, w3) as fetch,
        ):
            for s in [gh, fs, fetch]:
                await s.initialize()

            registry = await build_tool_registry({"github": gh, "fs": fs, "fetch": fetch})
            tool_defs = [v["anthropic_def"] for v in registry.values()]

            messages = [{"role": "user", "content": f"Review the pull request at {pr_url}. Use the available tools to fetch the PR details, diff, and any linked issues."}]

            while True:
                resp = client.messages.create(
                    model="claude-sonnet-5", max_tokens=4096,
                    tools=tool_defs, messages=messages,
                )
                messages.append({"role": "assistant", "content": resp.content})

                tool_uses = [b for b in resp.content if b.type == "tool_use"]
                if not tool_uses:
                    for block in resp.content:
                        if hasattr(block, "text"):
                            print(block.text)
                    break

                results = []
                for tu in tool_uses:
                    entry = registry[tu.name]
                    result = await entry["session"].call_tool(
                        entry["tool"].name, dict(tu.input)
                    )
                    results.append({
                        "type": "tool_result",
                        "tool_use_id": tu.id,
                        "content": result.content[0].text if result.content else "",
                        "is_error": result.isError,
                    })
                messages.append({"role": "user", "content": results})

asyncio.run(run_review_agent("https://github.com/acme/api/pull/42"))

